const fs = require('fs');
const { Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell, HeadingLevel } = require("docx");

const data = JSON.parse(fs.readFileSync('outputs/extracted_data.json', 'utf8'));
const key_metrics = data.key_metrics.slice(0, 10); // limit to 10

const doc = new Document({
  sections: [{
    children: [
      new Paragraph({
        text: "Financial Summary",
        heading: HeadingLevel.HEADING_1
      }),
      new Table({
        rows: key_metrics.map(metric => new TableRow({
          children: [new TableCell({
            children: [new Paragraph(metric)]
          })]
        }))
      }),
      new Paragraph({
        children: [
          new TextRun("NVIDIA has demonstrated robust financial performance in its first quarter fiscal 2024 results. "),
          new TextRun("The financial data extracted from the report shows significant revenue growth and key metrics that underscore the company's leadership in accelerated computing and generative AI.")
        ]
      })
    ]
  }]
});

Packer.toBuffer(doc).then(buffer => {
  fs.writeFileSync("outputs/summary.docx", buffer);
});
